    throw new Error('Title must be 200 characters or fewer.');
  }

  addPost(title, content);

  // Invalidate the 'posts' cache tag with read-your-own-writes semantics,
  // then clear the client-side router cache so the subsequent redirect
  // renders fresh data instead of stale HTML.
