import { updateTag, refresh } from 'next/cache';
import { redirect } from 'next/navigation';
import { addPost } from './posts';

export async function createPost(formData: FormData): Promise<void> {
  const title = formData.get('title')?.toString().trim();
  const content = formData.get('content')?.toString().trim();

  if (!title || !content) {
    throw new Error('Title and content are required.');
  }

  if (title.length > 200) {
    throw new Error('Title must be 200 characters or fewer.');
  }

  addPost(title, content);

  // Invalidate the 'posts' cache tag with read-your-own-writes semantics.
  // updateTag is the Server Action-specific invalidation API in Next.js 16 —
  // it guarantees the next server render fetches fresh data synchronously
  // (no stale-while-revalidate background trickle). This is the correct
  // choice over revalidateTag for mutations in Server Actions.
  updateTag('posts');

  // Clear the client-side router cache so the subsequent redirect
  // renders fresh data instead of serving stale HTML from the client cache.
  refresh();

  redirect('/');
}
"}
